const file = $input.item.json;
if (!file || !file.name) throw new Error('No file data');
const name = file.name.trim().toLowerCase();
let channel = "UNKNOWN";
if (name.includes("health")) channel = "HEALTH_HACKS";
else if (name.includes("money")) channel = "MONEYSTACK";
const ts = new Date().toISOString().split('T')[0].replace(/-/g,'');
const id = Math.random().toString(36).substring(2, 8);
return {videoId: `${channel.toLowerCase()}-${ts}-${id}`, channel, filename: file.name, driveId: file.id, detectedAt: new Date().toISOString()};

