    }
  });

  if (response.data.status === 'finished') {
    // Find export task
    const exportTask = response.data.tasks.find(t => t.name === 'export-audio');
    if (exportTask && exportTask.result) {
      return { audioUrl: exportTask.result.files[0].url };
    }
  }

  if (response.data.status === 'error') {
    throw new Error('CloudConvert job failed: ' + JSON.stringify(response.data));
  }

  // Wait before next check
  await new Promise(resolve => setTimeout(resolve, waitTime));
}

throw new Error('CloudConvert job timeout after 90 seconds');

const channel = $node['Extract Channel Info'].json.channel;
const transcript = $json.text;
const prompt = `You are a social media strategist. Generate unique titles/descriptions for this video.

CHANNEL: ${channel}
TRANSCRIPT: ${transcript}

Generate platform-specific content:

TIKTOK: Viral hook, casual tone, emoji-rich
INSTAGRAM: Aspirational story, relatable
YOUTUBE: SEO-optimized, educational

Output ONLY valid JSON: {"tiktok":{"title":"","caption":"","hashtags":[]},"instagram":{"title":"","caption":"","hashtags":[]},"youtube":{"title":"","description":"","tags":[]}}`;
return {prompt, channel, videoId: $node['Extract Channel Info'].json.videoId};

const response = $json.choices[0].message.content;
let content;
try {content = JSON.parse(response);} catch {content = JSON.parse(response.replace(/```json\n?/g,'').replace(/```/g,'').trim());}
return {tiktok: content.tiktok, instagram: content.instagram, youtube: content.youtube};

